import subprocess
import sys
import os

def run_command(command):
    result = subprocess.run(command, shell=True, check=True, capture_output=True, text=True)
    print(result.stdout)
    if result.stderr:
        print(result.stderr)

def main():
    try:
        # Install dependencies with security checks
        run_command(f"{sys.executable} -m pip install --upgrade pip")
        run_command(f"{sys.executable} -m pip install --upgrade setuptools wheel")
        run_command(f"{sys.executable} -m pip install -r requirements.txt --no-cache-dir")
        
        # Run tests
        run_command(f"{sys.executable} -m pytest tests/ -v")
        
        # Package for deployment
        run_command(f"{sys.executable} setup.py sdist bdist_wheel")
        
        print("Deployment workflow completed successfully.")
        
    except subprocess.CalledProcessError as e:
        print(f"Error occurred: {e}")
        sys.exit(1)
    except Exception as e:
        print(f"Unexpected error: {e}")
        sys.exit(1)

if __name__ == "__main__":
    main()